begin;
update public.security_codes set title_tr='Güvenlik Dosyasıyla İlişkili', description_tr='Açık bir idari/güvenlik dosyası bırakarak Türkiye''den çıkış yapılması.', how_to_remove_tr=NULL, duration_tr=NULL where code='178';
update public.security_codes set title_tr='Mahkeme Kodu', description_tr='Türk mahkemeleri önünde yasal işlemlere tabi tutulan ve adli kontrol kapsamında yurt dışına çıkış yasağı bulunan yabancılara konulur. Ancak yasağı veren yetkili mahkemenin kararıyla kaldırılabilir. Çıkışı engeller, girişi değil.', how_to_remove_tr='Yetkili mahkemeye başvurulması.', duration_tr='Mahkeme kararına bağlı' where code='A99';
update public.security_codes set title_tr='3 Aylık İhlal', description_tr='Vize, ikamet veya çalışma izni süresini 10 gün ile 3 ay arasında aşan yabancılara konulur. 3 aylık giriş yasağı ile birlikte Yabancılar ve Uluslararası Koruma Kanunu (YUKK) Madde 102 uyarınca idari para cezası uygulanır. Aşım süresine göre kademelenen Ç-101''den Ç-105''e kadar olan serinin en hafif kodudur.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğü üzerinden başvuru yapıldıktan sonra Türk konsolosluğundan özel meşruhatlı vize alınması ve sınıra varıldığında doğan cezanın ödenmesi. Yasak, sınır polisi tarafından otomatik olarak kaldırılır.', duration_tr='3 ay' where code='Ç101';
update public.security_codes set title_tr='6 Aylık İhlal', description_tr='Vize, ikamet veya çalışma izni süresini 3 ay ile 6 ay arasında aşan yabancılara konulur. 6 aylık giriş yasağı ile birlikte idari para cezası uygulanır. Kademeli Ç-101''den Ç-105''e kadar olan serinin ikinci kodudur.', how_to_remove_tr='Türk konsolosluğundan özel meşruhatlı vize alınması ve sınırda cezanın ödenmesi. Otomatik olarak kaldırılır.', duration_tr='6 ay' where code='Ç102';
update public.security_codes set title_tr='Bir Yıllık İhlal', description_tr='Vize, ikamet veya çalışma izni süresini 6 ay ile bir yıl arasında aşan yabancılara konulur. Bir yıllık giriş yasağı ile birlikte idari para cezası uygulanır.', how_to_remove_tr='Türk konsolosluğundan özel meşruhatlı vize alınması ve sınırda cezanın ödenmesi. Otomatik olarak kaldırılır.', duration_tr='Bir yıl' where code='Ç103';
update public.security_codes set title_tr='İki Yıllık İhlal', description_tr='Vize, ikamet veya çalışma izni süresini bir yıl ile iki yıl arasında aşan yabancılara konulur. İki yıllık giriş yasağı ile birlikte idari para cezası uygulanır.', how_to_remove_tr='Türk konsolosluğundan özel meşruhatlı vize alınması ve sınırda cezanın ödenmesi. Otomatik olarak kaldırılır.', duration_tr='İki yıl' where code='Ç104';
update public.security_codes set title_tr='5 Yıllık İhlal', description_tr='Vize, ikamet veya çalışma izni süresini iki yıldan fazla aşan yabancılara konulur. 5 yıllık giriş yasağı ile birlikte idari para cezası uygulanır. Ç-101''den Ç-105''e kadar olan serinin en ağır kodudur.', how_to_remove_tr='Türk konsolosluğundan özel meşruhatlı vize alınması ve sınırda cezanın ödenmesi. Otomatik olarak kaldırılır.', duration_tr='5 yıl' where code='Ç105';
update public.security_codes set title_tr='Yasa Dışı Giriş', description_tr='Türkiye''ye yasa dışı yollarla (resmi sınır kapısı olmadan sınırdan veya sahte belgelerle) giren ya da çıkan yabancılara konulur. YUKK Madde 102/a uyarınca 5 yıllık giriş yasağı ile birlikte idari para cezası uygulanır. Ceza ödenmezse ayrıca Ç-135 kodu eklenir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kararıyla ya da yasak süresinin dolması ve özel meşruhatlı vize alınmasının ardından kaldırılır.', duration_tr='5 yıl' where code='Ç113';
update public.security_codes set title_tr='Adli İşlem', description_tr='Türkiye''de devam eden adli işlemleri bulunan (henüz karara bağlanmamış cezai davalar) yabancılara konulur. İkamet izni iptal edilir ve iki yıllık giriş yasağı uygulanır. Beraat kararı verilmesi hâlinde doğan tüm kısıtlamalar otomatik olarak kaldırılır.', how_to_remove_tr='İsnat edilen suçtan beraat kararı verilmesi hâlinde doğan tüm kısıtlamalar kaldırılır. Aksi takdirde sürenin dolması ve özel meşruhatlı vize beklenir.', duration_tr='İki yıl' where code='Ç114';
update public.security_codes set title_tr='Tahliye', description_tr='Türkiye''de hapis cezasını çekip serbest bırakılan ve ardından sınır dışı edilen yabancılara konulur. Sınır dışı işleminden sonra iki yıllık giriş yasağı uygulanır. Genel Müdürlük, suçun türüne ve ağırlığına göre ayrıca G ve/veya N kodları ekleyebilir.', how_to_remove_tr='Suçtan beraat edilmesi hâlinde tüm kısıtlamalar kaldırılır. Genel Müdürlük, suçun türüne göre G ve/veya N kodu ekleyebilir.', duration_tr='İki yıl' where code='Ç115';
update public.security_codes set title_tr='Genel Ahlak', description_tr='Genel ahlak, genel sağlık veya kamu düzeni açısından tehdit oluşturduğuna dair haklarında karar verilen yabancılar hakkında konulur. YUKK''un 54/1-d maddesi uyarınca 5 yıl süreyle giriş yasağı doğurur.', how_to_remove_tr='Yasak süresinin dolmasını beklemek ve konsolosluktan özel vize almak.', duration_tr='5 yıl' where code='Ç116';
update public.security_codes set title_tr='Kaçak Çalışma', description_tr='Türkiye''de çalışma izni olmadan veya süresi dolmuş çalışma izniyle çalışan yabancılar hakkında konulur. İş Kanunu ve YUKK uyarınca 1 yıl süreyle giriş yasağının yanı sıra hem işçiye hem de işverene idari para cezası doğurur.', how_to_remove_tr='Yasak süresinin dolmasını beklemek ve konsolosluktan özel vize almak.', duration_tr='1 yıl' where code='Ç117';
update public.security_codes set title_tr='İkamet İptali (Sağlık)', description_tr='Sağlık nedenleriyle (genel sağlık açısından tehlike oluşturan bulaşıcı bir hastalık taşıması nedeniyle) ikamet izni iptal edilen yabancılar hakkında konulur. 5 yıl süreyle giriş yasağı doğurur. İyileşmeyi kanıtlayan resmi bir tıbbi rapor sunularak kaldırılabilir.', how_to_remove_tr='Bulaşıcı hastalık taşımadığını kanıtlayan, bir devlet hastanesinden alınmış tıbbi rapor temin etmek. Veya elçilikten apostil onaylı, yurt dışındaki bir hastaneden alınmış rapor sunmak.', duration_tr='5 yıl' where code='Ç118';
update public.security_codes set title_tr='Çalışma Cezası (Çalışan)', description_tr='Kaçak çalışma nedeniyle (çalışan sıfatıyla) haklarında idari para cezası verilen ve bu cezayı ödemeyen yabancılar hakkında konulur. Yasak, hem işçiye hem de işverene tahakkuk eden cezanın ödenmesine kadar yürürlükte kalır.', how_to_remove_tr='İşverene ve işçiye tahakkuk eden cezanın ödenmesi.', duration_tr='Ceza ödenene kadar' where code='Ç119';
update public.security_codes set title_tr='Vize Cezası', description_tr='Vize veya ikamet süresini aşmaları nedeniyle haklarında idari para cezası verilen ve bu cezayı ödemeyen yabancılar hakkında konulur. Ceza ödenene kadar giriş engellenir. Sınır kapısında ödeme yapıldığında otomatik olarak kaldırılır.', how_to_remove_tr='Vize/ikamet süresi aşımı cezasının ödenmesi.', duration_tr='Ceza ödenene kadar' where code='Ç120';
update public.security_codes set title_tr='Koruma Reddi', description_tr='Uluslararası koruma (iltica) başvuruları nihai olarak reddedilen ve Türkiye''den sınır dışı edilen başvuru sahipleri hakkında konulur. Göç İdaresi Genel Müdürlüğü tarafından yürütülür.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğü''ne başvurmak.', duration_tr='Belirsiz' where code='Ç129';
update public.security_codes set title_tr='Yabancılar Kanunu', description_tr='Türkiye''ye yasa dışı giriş veya çıkış nedeniyle (YUKK''un 102/a maddesi) haklarında idari para cezası verilen ve bu cezayı ödemeyen yabancılar hakkında konulur. Ödeme yapılana kadar yürürlükte kalır.', how_to_remove_tr='Yasa dışı giriş/çıkış cezasının ödenmesi.', duration_tr='Ceza ödenene kadar' where code='Ç135';
update public.security_codes set title_tr='Sınır Dışı Masrafları', description_tr='Seyahat veya sınır dışı masraflarını Türkiye Devleti''nin üstlendiği ve bu tutarı ödemeyen yabancılar hakkında konulur. Yasak, tahakkuk eden tüm masrafların ödenmesine kadar yürürlükte kalır.', how_to_remove_tr='Tahakkuk eden sınır dışı masraflarının ödenmesi.', duration_tr='Ödeme yapılana kadar' where code='Ç136';
update public.security_codes set title_tr='Süre Aşımı', description_tr='Haklarında çıkışa davet (Terke Davet / V-137) kararı verilen, tanınan süreyi çıkış yapmadan aşan ve ardından haklarında para cezası verilip bu cezayı ödemeyen yabancılar hakkında konulur. Ödeme yapılana kadar yürürlükte kalır.', how_to_remove_tr='Tanınan sürenin aşılması nedeniyle verilen cezanın ödenmesi.', duration_tr='Ceza ödenene kadar' where code='Ç137';
update public.security_codes set title_tr='INAD', description_tr='Kabul edilmeyen yolcular (INAD Yolcu) hakkında konulur — bunlar, havalimanına veya sınıra ulaşan, girişi reddedilerek derhal çıkış ülkesine geri gönderilen kişilerdir. Genel Müdürlük tarafından yürütülür.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğü''ne başvurmak.', duration_tr='Belirsiz' where code='Ç138';
update public.security_codes set title_tr='Uluslararası Yasak', description_tr='Uluslararası güvenlik riski olarak sınıflandırılan yabancılara (istihbarat raporlarına veya terör örgütleriyle bağlantıya dayanarak) uygulanır. 5 yıl süreyle giriş yasağı getirir ve özel meşruhatlı vize ile kaldırılamaz; yalnızca Göç İdaresi Genel Müdürlüğü kararıyla kaldırılır. En tehlikeli yasak kodlarından biridir.', how_to_remove_tr='Özel meşruhatlı vize alınsa dahi bu vize ile kaldırılamaz. Yalnızca Göç İdaresi Genel Müdürlüğü kararıyla kaldırılır.', duration_tr='5 yıl' where code='Ç141';
update public.security_codes set title_tr='Kamu Güvenliği', description_tr='YUKK''nun 54/1 maddesi uyarınca kamu güvenliği için tehdit olarak sınıflandırılan yabancılara uygulanır. 5 yıl süreyle giriş yasağı getirir ve özel meşruhatlı vize ile kaldırılamaz. Türkiye''yi çatışma bölgelerine geçiş güzergâhı olarak kullandığından şüphelenilen kişileri de kapsar.', how_to_remove_tr='Özel meşruhatlı vize ile kaldırılamaz. Yalnızca Göç İdaresi Genel Müdürlüğü kararıyla kaldırılır. Gönüllü geri dönüş yapmak isteyen geçici koruma kapsamındaki kişiler için: il müdürlüğü aracılığıyla eklenir.', duration_tr='5 yıl' where code='Ç149';
update public.security_codes set title_tr='Sahte Belge', description_tr='Türk makamlarına sahte veya tahrif edilmiş resmi belgeler (pasaport, vize, sertifika) sunan yabancılara uygulanır. 5 yıl süreyle giriş yasağı getirir. Ancak kişinin sahteciliğin bilgisi veya iradesi dışında yapıldığını ispatlaması hâlinde kaldırılabilir.', how_to_remove_tr='Kişi, sahte belgenin kullanımının iradesi dışında gerçekleştiğini ispatlar ve kabul edilebilir belgeler sunarsa kod kaldırılır.', duration_tr='5 yıl' where code='Ç150';
update public.security_codes set title_tr='İnsan Kaçakçılığı', description_tr='Göçmen kaçakçılığı veya insan ticareti suçlarına karışan yabancılara uygulanır. YUKK''nun 54/1-d maddesi uyarınca 5 yıl süreyle giriş yasağı getirir.', how_to_remove_tr='Yasak süresinin dolmasının beklenmesi + özel meşruhatlı vize. Başka suçlara karışılmamışsa Ç-114 veya Ç-115 eklenmez.', duration_tr='5 yıl' where code='Ç151';
update public.security_codes set title_tr='Tedbir Amaçlı Yasak', description_tr='İhlal işlemesi beklenen yabancılara tedbir (önleyici) amaçlı yasak olarak uygulanır. 1 yıl süreyle giriş yasağı getirir. Süre bittikten sonra Genel Müdürlük kararıyla kaldırılır.', how_to_remove_tr='Süre bittikten sonra Göç İdaresi Genel Müdürlüğü kararıyla kaldırılır.', duration_tr='1 yıl' where code='Ç152';
update public.security_codes set title_tr='Gerekçelendirememe', description_tr='Sınır kapısında Türkiye''ye geliş sebebini gerekçelendiremeyen (belgelerin yetersizliği veya amacın belirsizliği) yabancılara uygulanır. 1 yıl süreyle giriş yasağı getirir.', how_to_remove_tr='Yasak süresinin dolmasının beklenmesi + konsolosluktan özel meşruhatlı vize alınması.', duration_tr='1 yıl' where code='Ç166';
update public.security_codes set title_tr='Bir Aylık Yasak', description_tr='Basit bir ihlal işleyen (10 günden az aşım) yabancılara uygulanır. Yalnızca 1 ay süreyle giriş yasağı + küçük bir para cezası getirir. Giriş yasağı kodlarının en hafifidir.', how_to_remove_tr='Özel meşruhatlı vize alınması + sınırda cezanın ödenmesi. Otomatik olarak kaldırılır.', duration_tr='1 ay' where code='Ç167';
update public.security_codes set title_tr='Sağlık Vizesi', description_tr='Geçici koruma sistemini ihlal eden, geçici koruma kapsamındaki kişilere (çoğunlukla Suriyeliler) uygulanır. 5 yıl süreyle giriş yasağı getirir.', how_to_remove_tr='Yasak süresinin dolmasının beklenmesi + özel meşruhatlı vize.', duration_tr='5 yıl' where code='Ç179';
update public.security_codes set title_tr='Çatışma Bölgeleriyle Bağlantı', description_tr='DEAŞ (IŞİD) örgütüyle bağlantılı yabancılara uygulanır. En tehlikeli güvenlik yasağı kodlarından biridir. Yalnızca Göç İdaresi Genel Müdürlüğü tarafından, güvenlik birimleriyle koordineli olarak yürütülür.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğüne başvuru.', duration_tr='Belirsiz' where code='Ç184';
update public.security_codes set title_tr='Diğer Suçlar', description_tr='Yakın zamanda eklenmiş bir devlet güvenliği kodudur. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı getirir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararıyla' where code='G208';
update public.security_codes set title_tr='Yasaklı örgütler', description_tr='Yabancılar ve Uluslararası Koruma Kanunu (YUKK) 54/1. maddesi uyarınca kamu düzeni veya kamu güvenliği açısından tehdit olarak değerlendirilen yabancılara uygulanır. Yalnızca Göç İdaresi Genel Müdürlüğü kararıyla kaldırılabilen süresiz giriş yasağıdır. Kod korunmak kaydıyla, özel yazılı talimatla istisnai ve geçici giriş izni verilebilir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir. Genel Müdürlüğün yazılı talimatıyla, kod korunmak kaydıyla geçici giriş izni verilebilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G26';
update public.security_codes set title_tr='Sahtecilik', description_tr='Terör örgütü üyesi olan veya bu örgütlere mensubiyetinden şüphelenilen yabancılara uygulanır. YUKK 54/1-b maddesi uyarınca Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır. En ağır G kodlarından biridir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G34';
update public.security_codes set title_tr='Uyuşturucu', description_tr='Uyuşturucu suçlarına (ticaret, kullanım, bulundurma veya kaçakçılık) karışan yabancılara uygulanır. YUKK 54/1-b maddesi uyarınca Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G42';
update public.security_codes set title_tr='Kaçakçılık', description_tr='Kültürel ve tarihi eserlerin, hazinelerin ya da yasak malların kaçakçılığına karışan yabancılara uygulanır. Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G43';
update public.security_codes set title_tr='Fuhuş', description_tr='Ruhsatsız silah veya patlayıcı bulundurma ya da kaçakçılığına karışan yabancılara uygulanır. YUKK 54/1-b maddesi uyarınca Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G48';
update public.security_codes set title_tr='Mali yolsuzluk', description_tr='Cinsel suç işlediği hükmen sabit olan veya bu suçları işlediğinden şüphelenilen yabancılara uygulanır. Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G55';
update public.security_codes set title_tr='Adam öldürme', description_tr='Adam öldürme suçundan hüküm giymiş veya bu suçu işlediğinden şüphelenilen yabancılara uygulanır. YUKK 54/1-b maddesi uyarınca Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G58';
update public.security_codes set title_tr='Tehdit', description_tr='Hırsızlık suçundan hüküm giymiş veya bu suçu işlediğinden şüphelenilen yabancılara uygulanır. Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G64';
update public.security_codes set title_tr='Hırsızlık', description_tr='Dolandırıcılık veya sahtekârlık suçundan hüküm giymiş ya da bu suçu işlediğinden şüphelenilen yabancılara uygulanır. Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G65';
update public.security_codes set title_tr='Yağma', description_tr='Resmi belgede sahtecilik suçundan hüküm giymiş veya bu suçu işlediğinden şüphelenilen yabancılara uygulanır. Genel Müdürlük kararıyla verilen süresiz giriş yasağıdır.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G66';
update public.security_codes set title_tr='Dolandırıcılık', description_tr='Önceki kodlarda sınıflandırılmamış diğer adli suçlardan mahkûm olan yabancılara uygulanır. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı konur.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G67';
update public.security_codes set title_tr='Bulaşıcı hastalıklar', description_tr='Türkiye''ye karşı casusluk veya istihbarat faaliyetlerinde bulundukları şüphesiyle yabancılara uygulanır. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı konur. En tehlikeli G kodlarından biridir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G78';
update public.security_codes set title_tr='İstihbarat kodu', description_tr='Interpol aracılığıyla uluslararası düzeyde aranan veya sınır aşan uluslararası suçlara karışan yabancılara uygulanır. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı konur.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G82';
update public.security_codes set title_tr='Kamu güvenliğine tehdit', description_tr='Türkiye Devleti''nin güvenliğine tehdit olarak sınıflandırılan yabancılara uygulanır (en yüksek güvenlik seviyesi). Terör örgütleriyle irtibatlı oldukları veya ulusal güvenliği tehdit eden faaliyetlerle bağlantılı oldukları şüphesi taşıyanları kapsar. Süresiz giriş yasağı — yalnızca Genel Müdürlük kaldırabilir. En çok araştırılan ve tartışılan kodlardan biridir.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir. Özel yazılı talimatla geçici giriş izni verilebilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G87';
update public.security_codes set title_tr='Terörist savaşçı', description_tr='Haklarında YUKK''nin 54. maddesi uyarınca Türkiye''den sınır dışı etme kararı (Sınır Dışı Etme Kararı) verilen yabancılara uygulanır. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı konur.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G89';
update public.security_codes set title_tr='Diğer suçlar', description_tr='Türk İstihbarat Teşkilatı''nın (MİT) veya yetkili bir güvenlik biriminin doğrudan talebi üzerine yabancılara uygulanır. Göç İdaresi Genel Müdürlüğü kararıyla süresiz giriş yasağı konur.', how_to_remove_tr='Yalnızca Göç İdaresi Genel Müdürlüğü kaldırabilir.', duration_tr='Belirsiz — Genel Müdürlük kararına bağlı' where code='G99';
update public.security_codes set title_tr='Para kaçakçılığı', description_tr='Sınırdan giriş-çıkış hareketlerinin izlenmesiyle ilgili özel bir güvenlik kodudur. Yetkili güvenlik birimleri (polis veya istihbarat) tarafından konur ve yalnızca kodu koyan aynı birim tarafından gözden geçirilir.', how_to_remove_tr='Yetkili güvenlik birimlerine başvuru yapılması.', duration_tr='Belirsiz' where code='K113';
update public.security_codes set title_tr='Çıkış yasağı', description_tr='Geçerli bir çalışma izni olmadan Türkiye''de çalışan yabancılara ve onları çalıştıran işverenlere uygulanan idari para cezasıdır. Cezanın her iki tarafça da ödenmesine kadar geçerliliğini korur.', how_to_remove_tr='Çalışma izni olmadan çalışma cezasının ödenmesi. Ödeme yapıldığında kaldırılır.', duration_tr='Ceza ödenene kadar' where code='N119';
update public.security_codes set title_tr='Vize/ikamet/çalışma cezası', description_tr='YUKK''nin 102. maddesi uyarınca vize, ikamet veya çalışma izni süresini aşan yabancılara uygulanan idari para cezasıdır. En yaygın N kodlarından biridir. Ceza sınır kapısında veya yerel müdürlükte ödendiğinde otomatik olarak kaldırılır.', how_to_remove_tr='Vize/ikamet/çalışma izni süresini aşma cezasının ödenmesi. Sınır kapısında ödeme yapıldığında otomatik olarak kaldırılır.', duration_tr='Ceza ödenene kadar' where code='N120';
update public.security_codes set title_tr='Uluslararası koruma kanununun ihlali', description_tr='Türkiye''ye yasa dışı yollarla girmeye veya çıkmaya çalışan yabancılara uygulanan idari para cezasıdır (YUKK''nin 102/a maddesi uyarınca). Ödeme yapılana kadar geçerliliğini korur.', how_to_remove_tr='Yasa dışı giriş/çıkış cezasının ödenmesi.', duration_tr='Ceza ödenene kadar' where code='N135';
update public.security_codes set title_tr='Sınır Dışı (Tehcir) Masrafları', description_tr='Seyahat veya sınır dışı edilme masrafları Türkiye Devleti tarafından karşılanan yabancılar hakkında kaydedilir. Yeniden girişe izin verilmeden önce tutarın tamamının ödenmesi gerekir.', how_to_remove_tr='Devlet tarafından karşılanan seyahat/sınır dışı etme masraflarının ödenmesi.', duration_tr='Ödeme yapılana kadar' where code='N136';
update public.security_codes set title_tr='Çıkışa Davet', description_tr='Çıkışa davet kararına (V-137) bağlı idari bir kayıttır. Hakkında V-137 kararı verilen yabancıların takibi ve belirlenen süre içinde çıkış yükümlülüğüne uymalarının teyidi için kullanılır.', how_to_remove_tr='Yerel Göç İdaresi Müdürlüğüne başvurulması.', duration_tr='Belirsiz' where code='N137';
update public.security_codes set title_tr='İdari Gözetim Cezası', description_tr='Yabancılar Kanunu''nun (YUKK) 102. maddesinin (ç) bendi uyarınca uygulanan idari para cezasıdır. İkamet veya çalışma şartlarına uyum konusundaki belirli ihlallerle ilgilidir. Ceza ödenene kadar geçerliliğini korur.', how_to_remove_tr='102. maddenin (ç) bendinin ihlaline ilişkin cezanın ödenmesi.', duration_tr='Ceza ödenene kadar' where code='N168';
update public.security_codes set title_tr='Bakanlık Cezası', description_tr='İçişleri Bakanlığı veya Göç İdaresi tarafından belirlenen idari talimatlara uymayan yabancılara uygulanan idari para cezasıdır. Kayıt şartlarını ihlal eden geçici koruma kapsamındaki kişileri de içerir. V-165 ve V-173 kodları ile ilişkilidir.', how_to_remove_tr='Bakanlık tarafından belirlenen idari talimatlara uyulmamasına ilişkin cezanın ödenmesi.', duration_tr='Ceza ödenene kadar' where code='N169';
update public.security_codes set title_tr='Kabahatler Kanunu Cezası', description_tr='Yabancılar Kanunu (YUKK) uyarınca uygulanan çeşitli idari para cezalarıdır. Önemli not: Yabancı Türkiye dışındayken kod girilirse, durumunu etkilemez ve girişine engel olmaz — yalnızca çıkış yapmaya çalıştığında etkili olur.', how_to_remove_tr='Uygulanan cezanın ödenmesi. Not: Yabancı Türkiye dışındayken kod girilirse durumunu etkilemez.', duration_tr='Ceza ödenene kadar' where code='N170';
update public.security_codes set title_tr='Ödenmemiş Ceza', description_tr='YUKK''un 57/A maddesi uyarınca idari gözetime alternatif tedbirlere (periyodik imza, belirli bir adreste ikamet) uymayan yabancılara uygulanan idari para cezasıdır. V-144 ve V-160 kodları ile ilişkilidir.', how_to_remove_tr='İdari gözetime alternatif tedbirlere uyulmamasına ilişkin cezanın ödenmesi.', duration_tr='Ceza ödenene kadar' where code='N171';
update public.security_codes set title_tr='Gönüllü Geri Dönüş Masrafları', description_tr='Gönüllü geri dönüş programı kapsamında seyahat masrafları Türkiye Devleti tarafından karşılanan yabancılar hakkında kaydedilir. Tutarın tamamı ödenene kadar geçerliliğini korur. V-145 kodu ile ilişkilidir.', how_to_remove_tr='Gönüllü geri dönüşe ilişkin seyahat masraflarının ödenmesi.', duration_tr='Ödeme yapılana kadar' where code='N172';
update public.security_codes set title_tr='Örgütler (İzin)', description_tr='Girişe izin verilmeden önce Göç İdaresi Genel Müdürlüğünden ön izin alınmasını gerektiren bir güvenlik ihbarıdır. Kod sistemde kalır, ancak konsolosluktan Özel Meşruhatlı Vize alınması halinde girişe izin verilir.', how_to_remove_tr='Genel Müdürlükten ön izin alındıktan sonra konsolosluktan Özel Meşruhatlı Vize alınması. Kod kalır ancak girişe izin verilir.', duration_tr='Belirsiz' where code='N26';
update public.security_codes set title_tr='Sahtecilik (İzin)', description_tr='Terörle bağlantılı olup, girişe izin verilmeden önce Göç İdaresi Genel Müdürlüğünden ön izin alınmasını gerektiren bir güvenlik ihbarıdır. Kişi Özel Meşruhatlı Vize alsa bile kod sistemde kalır. G-34 kodu (terör nedeniyle kalıcı giriş yasağı) ile ilişkilidir.', how_to_remove_tr='Genel Müdürlükten ön izin alındıktan sonra konsolosluktan Özel Meşruhatlı Vize alınması.', duration_tr='Belirsiz' where code='N34';
update public.security_codes set title_tr='Uyuşturucu (İzin)', description_tr='Uyuşturucu suçlarıyla bağlantılı olup, girişe izin verilmeden önce Genel Müdürlükten ön izin alınmasını gerektiren bir güvenlik ihbarıdır. G-42 kodu (uyuşturucu nedeniyle kalıcı giriş yasağı) ile ilişkilidir. Girişe yalnızca Özel Meşruhatlı Vize ile izin verilir.', how_to_remove_tr='Genel Müdürlükten ön izin alındıktan sonra konsolosluktan Özel Meşruhatlı Vize alınması.', duration_tr='Belirsiz' where code='N42';
update public.security_codes set title_tr='Kaçakçılık (İzin)', description_tr='Kaçakçılık suçlarıyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-43 koduyla ilişkilidir (kaçakçılık nedeniyle kalıcı giriş yasağı). Girişe yalnızca özel vize ile izin verilir.', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N43';
update public.security_codes set title_tr='Fuhuş (İzin)', description_tr='Silah suçlarıyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-48 koduyla ilişkilidir (ruhsatsız silah bulundurma nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N48';
update public.security_codes set title_tr='Cinayet (İzin)', description_tr='Cinayet suçuyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-58 koduyla ilişkilidir (cinayet nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N58';
update public.security_codes set title_tr='Tehdit (İzin)', description_tr='Hırsızlık suçuyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-64 koduyla ilişkilidir (hırsızlık nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N64';
update public.security_codes set title_tr='Hırsızlık (İzin)', description_tr='Dolandırıcılık veya sahtekârlık suçuyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-65 koduyla ilişkilidir (dolandırıcılık nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N65';
update public.security_codes set title_tr='Yağma (İzin)', description_tr='Belge sahteciliği suçuyla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-66 koduyla ilişkilidir (sahtecilik nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N66';
update public.security_codes set title_tr='Dolandırıcılık (İzin)', description_tr='Diğer adli suçlarla bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-67 koduyla ilişkilidir (çeşitli adli suçlar nedeniyle kalıcı giriş yasağı).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N67';
update public.security_codes set title_tr='Hastalıklar (İzin)', description_tr='Casusluk veya istihbarat faaliyetleriyle bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-78 koduyla ilişkilidir (casusluk nedeniyle kalıcı giriş yasağı). Güvenlik açısından hassas kodlardan biridir.', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N78';
update public.security_codes set title_tr='Milli Güvenlik (İzin)', description_tr='Interpol talebi veya uluslararası suçlarla bağlantılı güvenlik şerhi. Girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektirir. Girişe yalnızca özel vize ile izin verilir.', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N82';
update public.security_codes set title_tr='Kamu Güvenliği (İzin)', description_tr='Devlet güvenliğine yönelik tehditle bağlantılı, girişe izin verilmeden önce Genel Müdürlükten ön izin (istizan) alınmasını gerektiren güvenlik şerhi. G-87 koduyla ilişkilidir (kalıcı giriş yasağı — en yüksek güvenlik seviyesi).', how_to_remove_tr='Genel Müdürlükten istizan (ön izin) alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N87';
update public.security_codes set title_tr='Giriş Cezası', description_tr='Yabancılar ve Uluslararası Koruma Kanunu (YUKK) uyarınca uygulanan genel bir idari para cezasıdır. Ödeme sınır kapısında veya yerel müdürlük aracılığıyla yapıldığında otomatik olarak kaldırılır.', how_to_remove_tr='Para cezasının ödenmesi. Ödeme sınır kapısında veya yerel müdürlük aracılığıyla yapıldığında otomatik olarak kaldırılır.', duration_tr='Para cezası ödenene kadar' where code='N95';
update public.security_codes set title_tr='Süre Aşımı ve Ödeme', description_tr='Hakkında çıkışa davet (terke davet) kararı verilen (V-137) ve belirlenen süre içinde (15-30 gün) ülkeyi terk etmeyen yabancılara uygulanan idari para cezasıdır. Kod, para cezası ödenene kadar geçerliliğini korur. Çıkışta ödeme yapılmaması durumunda gelecekte ülkeye girişe izin verilmez.', how_to_remove_tr='Belirlenen süre içinde ülkeyi terk etmeme nedeniyle uygulanan para cezasının ödenmesi. Ödeme yapıldığında kaldırılır.', duration_tr='Para cezası ödenene kadar' where code='N96';
update public.security_codes set title_tr='Adres İhlali', description_tr='İkamet adresindeki değişikliği yasal süre içinde (20 iş günü) göç idaresine bildirmeyen yabancılara uygulanan idari para cezasıdır. Ödeme yapıldığında kaldırılır ve beraberinde V-71 kodu da kaldırılır.', how_to_remove_tr='Adres değişikliğini bildirmeme nedeniyle uygulanan para cezasının ödenmesi. Ödeme yapıldığında kaldırılır ve beraberinde V-71 kodu da kaldırılır.', duration_tr='Para cezası ödenene kadar' where code='N97';
update public.security_codes set title_tr='İnsan Ticareti Mağduru', description_tr='İnsan ticareti mağdurlarına özel bir kayıttır. Bu kişilere özel koruma ve hukuki yardım sağlanır. Yalnızca Göç İdaresi Genel Müdürlüğü tarafından yürütülür.', how_to_remove_tr='İnsan ticareti mağdurlarıyla ilgilidir. Genel Müdürlük tarafından yürütülür.', duration_tr='Belirsiz' where code='N98';
update public.security_codes set title_tr='İnterpol', description_tr='Türk istihbarat teşkilatı (MİT) veya yetkili bir güvenlik biriminin talebi üzerine çıkarılan bir güvenlik bildirimidir. Girişe izin verilmeden önce Genel Müdürlükten ön izin alınmasını gerektirir. G-99 koduyla bağlantılıdır.', how_to_remove_tr='Genel Müdürlükten ön izin alındıktan sonra konsolosluktan özel vize alınması.', duration_tr='Belirsiz' where code='N99';
update public.security_codes set title_tr='Koruma Başvurusunun Geri Çekilmesi', description_tr='Uluslararası koruma başvurusunu kendi isteğiyle geri çeken veya başvurusu geri çekilmiş sayılan yabancılara uygulanır. Bir yıl süreyle yeni başvuru yapılması yasaklanır.', how_to_remove_tr='Belirlenen sürenin (bir yıl) dolması. Yeni bir uluslararası koruma başvurusu yapılabilir.', duration_tr='Bir yıl' where code='O100';
update public.security_codes set title_tr='Uluslararası Koruma Reddi', description_tr='Uluslararası koruma (iltica) başvurusu resmen reddedilen yabancılara uygulanır. 3 yıl süreyle yeni başvuru yapılması yasaklanır.', how_to_remove_tr='Belirlenen sürenin (3 yıl) dolması. Yeni bir uluslararası koruma başvurusu yapılabilir.', duration_tr='3 yıl' where code='O176';
update public.security_codes set title_tr='Nihai Uluslararası Koruma Reddi', description_tr='Uluslararası koruma başvurusu nihai olarak reddedilen veya kendisine tanınan koruma statüsü iptal edilen yabancılara uygulanır. 5 yıl süreyle yeni başvuru yapılması yasaklanır. En ağır O kodudur.', how_to_remove_tr='Belirlenen sürenin (5 yıl) dolması. Yeni bir uluslararası koruma başvurusu yapılabilir.', duration_tr='5 yıl' where code='O177';
update public.security_codes set title_tr='Yeniden Yerleştirme', description_tr='Birleşmiş Milletler Mülteciler Yüksek Komiserliği (UNHCR) ile koordineli olarak üçüncü bir ülkeye (örneğin Kanada, Almanya, Avustralya) yeniden yerleştirme programı kapsamında kayıtlı yabancılara uygulanır.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğüne başvurulması.', duration_tr='Belirsiz' where code='O199';
update public.security_codes set title_tr='Çıkışa Davet', description_tr='Vize, ikamet veya çalışma izni ihlali nedeniyle hakkında çıkışa davet (terke davet) kararı verilen yabancılara uygulanır. Gönüllü çıkış için 15-30 gün süre tanınır. Çıkış yapıldığında sınır polisi tarafından otomatik olarak kaldırılır. Süre içinde çıkış yapılmazsa N-96 (para cezası) ve süre aşımının uzunluğuna göre Ç kodu (Ç-101''den Ç-105''e kadar) eklenir. En yaygın kodlardan biridir.', how_to_remove_tr='Belirlenen süre içinde ülkeyi terk etmek ve para cezasını ödemek. Çıkışta sınır polisi tarafından otomatik olarak kaldırılır. Sürenin aşılması durumunda: N-96 ve süre aşımının uzunluğuna göre Ç kodu eklenir.', duration_tr='Tanınan süreye göre' where code='V137';
update public.security_codes set title_tr='Şartlı salıverilme', description_tr='YUKK''un 57/A maddesi uyarınca, alternatif yükümlülüklerle (belirli aralıklarla imza atma, belirli bir adreste ikamet) geri gönderme merkezinden şartlı olarak salıverilen yabancılara konulur. Yükümlülüklere uyulmaması veya kaçış hâlinde V-160 + N-171 eklenir.', how_to_remove_tr='İdari gözetime alternatif tedbirlere uyulması (Madde 57/A). Yükümlülüklere uyulmaması veya kaçış hâlinde: V-160 + N-171 eklenir. Gönüllü çıkış hâlinde: sınır polisi tarafından kaldırılır.', duration_tr='Mahkeme kararına bağlı' where code='V144';
update public.security_codes set title_tr='Gönüllü geri dönüş (özel)', description_tr='Menşe ülkelerine gönüllü geri dönüş işlemlerini tamamlayan yabancılar için kaydedilir. Sistemde kalıcı kayıt olarak kalır. İnsan ticareti mağdurlarını ve düzensiz göçmenleri kapsar.', how_to_remove_tr='Gönüllü geri dönüş işlemleri tamamlandığında eklenir. Yerel müdürlük tarafından yürütülür.', duration_tr='Kalıcı — kayıt' where code='V145';
update public.security_codes set title_tr='Sahte pasaport', description_tr='Üzerinde şerh bulunan (sahte veya sorunlu) bir Türk pasaportu taşıyan yabancılara konulur. Sınıra varıldığında, uygun işlemin belirlenmesi için notlarda belirtilen güvenlik birimiyle iletişime geçilir.', how_to_remove_tr='Yerel veya genel müdürlük tarafından konulur. Sınıra varıldığında: notlarda belirtilen güvenlik birimiyle iletişime geçilir.', duration_tr='Belirsiz' where code='V146';
update public.security_codes set title_tr='Türk vatandaşının eşi', description_tr='Türk vatandaşlarıyla evli olup güvenlik incelemesi istenen yabancılara konulur. Sınıra varıldığında, kodun notlarında belirtilen güvenlik birimiyle iletişime geçilir. V-146''ya benzer, ancak evlilik durumlarına özgüdür.', how_to_remove_tr='V-146 gibidir. Kodun notlarında belirtilen güvenlik birimiyle iletişime geçilir.', duration_tr='Belirsiz' where code='V147';
update public.security_codes set title_tr='Barınma merkezleri', description_tr='Geçici Barınma Merkezleri''nde ikamet eden yabancılara konulur. Merkezdeki ikamet süresi boyunca geçerli kalır ve merkezden ayrılırken yerel müdürlükle koordinasyon içinde kaldırılır.
Geçici koruma altındaki yabancının ülkeden çıkışı bir izne bağlıdır. Bu kod genellikle geçici barınma merkezlerinde (kamplarda) ikamet etmiş kişilere konulur; verilerinizde belirtilen "Kahramanmaraş" barınma merkezi gibi. Bu, kişinin göç idaresinden resmi bir onay almadan Türkiye''den ayrılamayacağı (ister Suriye''ye dönüş için ister başka bir ülkeye seyahat için) anlamına gelir.', how_to_remove_tr='Geçici barınma merkezinden ayrılırken yerel müdürlüğe başvurulması.', duration_tr='Merkezdeki ikamet süresi' where code='V148';
update public.security_codes set title_tr='Sınır dışı durdurma (AYM)', description_tr='Anayasa Mahkemesi''nin (AYM) yabancının sınır dışı edilmesini geçici olarak durdurma kararı (tedbir kararı) verdiğinde konulur. Mahkemeden nihai karar çıkana kadar sınır dışı işleminin uygulanmasını engeller.', how_to_remove_tr='Anayasa Mahkemesi kararının sona ermesinin ardından genel müdürlük kararıyla kaldırılır.', duration_tr='Mahkeme kararına bağlı' where code='V153';
update public.security_codes set title_tr='Sınır dışına itiraz', description_tr='Sınır dışı etme kararına karşı İdare Mahkemesi''nde itirazda (dava) bulunan yabancılara konulur. Nihai bir karar çıkana kadar sınır dışı işlemini geçici olarak durdurur. Yabancıların haklarının korunması bakımından en önemli kodlardan biridir.', how_to_remove_tr='Sınır dışı işlemini geçici olarak durdurur. İdare Mahkemesi''nden nihai karar çıktığında kaldırılır.', duration_tr='Nihai karara kadar' where code='V154';
update public.security_codes set title_tr='Sınır dışı durdurma (Avrupa)', description_tr='Avrupa İnsan Hakları Mahkemesi''nin (AİHM) yabancının sınır dışı edilmesini durdurma kararı verdiğinde konulur. Mahkemeden nihai karar çıkana kadar sınır dışı işleminin uygulanmasını engeller.', how_to_remove_tr='Avrupa İnsan Hakları Mahkemesi kararının sona ermesinin ardından genel müdürlük kararıyla kaldırılır.', duration_tr='Mahkeme kararına bağlı' where code='V155';
update public.security_codes set title_tr='Avukat vekaleti', description_tr='Yabancı için hukuki temsilin (avukat) varlığını belgelemek amacıyla sisteme kaydedilen bir nottur. Ücretsiz hukuki yardım hâllerinde devlet üzerine tahakkuk eden avukatlık ücretlerinin ödenmesiyle ilgilidir.', how_to_remove_tr='Tahakkuk eden avukatlık ücretlerinin ödenmesi.', duration_tr='Ödeme yapılana kadar' where code='V156';
update public.security_codes set title_tr='İkamet reddi', description_tr='İkamet başvurusu reddedilen yabancılara konulur. Giriş ve çıkışı engellemez — ayrılırken otomatik olarak kaldırılır. Ancak retten itibaren 10 gün içinde ülkeden ayrılmazsa: aşım süresine göre Ç kodu + ödeme yapmayanlar için N-120 eklenir.', how_to_remove_tr='Giriş ve çıkışı engellemez — ayrılırken otomatik olarak kaldırılır. 10 gün içinde ayrılmazsa: süreye göre Ç kodu + ödeme yapmayanlar için N-120 eklenir.', duration_tr='10 gün' where code='V157';
update public.security_codes set title_tr='Misyon Kartı İptali', description_tr='Yabancı misyon çalışanlarının (diplomatlar ve elçilik personeli) veya aile bireylerinin kimlik kartı iptal edilen yabancılara konulur. Giriş yapmak istediklerinde "kabul edilmeyen yolcu" olarak işlem görür ve normal vize almaya yönlendirilir.', how_to_remove_tr='Giriş yapmak istediğinde: "kabul edilmeyen yolcu" olarak işlem görür ve vize almaya yönlendirilir.', duration_tr='Belirsiz' where code='V158';
update public.security_codes set title_tr='Transit', description_tr='Üçüncü bir ülkeye geçiş (transit) amacıyla Türkiye''ye giriş yapan yabancılara sınır polisi tarafından konulur. Yabancı nihai varış noktasına ulaşmak üzere Türkiye''den ayrılana kadar geçerli kalan geçici bir koddur.', how_to_remove_tr='Üçüncü bir ülkeye geçiş amacıyla Türkiye''ye giriş yapanlara sınır polisi tarafından eklenir.', duration_tr='Geçici — geçiş yapılana kadar' where code='V159';
update public.security_codes set title_tr='Adres Dondurma', description_tr='Göç İdaresi''nde kayıtlı adreste bulunmayan (kaçak veya bulunduğu yer bilinmeyen) yabancılara konulur. Ayrıca seyahat izni olmaksızın kendi ilinin dışında yakalanan yabancılara da uygulanır.', how_to_remove_tr='Göç İdaresi''ne başvurularak adresin yeniden tespit edilmesi ve Göç İdaresi''nin son güncellemelerine göre 11604 lira olan idari para cezasının ödenmesinin ardından kaldırılır.', duration_tr='Kişi bulunana veya adresi yeniden tespit edilene kadar' where code='V160';
update public.security_codes set title_tr='Sınır Dışı Yasağı (Menşe Ülke)', description_tr='Anayasa Mahkemesi''nin (AYM), yabancının özellikle menşe ülkesine sınır dışı edilmesini yasaklayan bir karar vermesi durumunda konulur (geri göndermeme ilkesi). Yalnızca menşe ülkeye sınır dışı etmeyi engeller, diğer ülkelere değil.', how_to_remove_tr='Anayasa Mahkemesi kararının sona ermesinin ardından Genel Müdürlük kararıyla kaldırılır.', duration_tr='Mahkeme kararına göre' where code='V161';
update public.security_codes set title_tr='İdari Gözetim Sonlandırma', description_tr='Geri gönderme merkezindeki idari gözetimlerinin sonlandırılmasına mahkeme tarafından karar verilen yabancılara konulur. Gönüllü çıkış halinde sınır polisi tarafından kaldırılır. Yeni bir sebep ortaya çıkarsa yeni bir idari gözetim kararı verilebilir.', how_to_remove_tr='Gönüllü çıkış halinde: sınır polisi tarafından kaldırılır ve genel kurallara göre işlem görür. İdari gözetim için yeni bir sebep ortaya çıktığında: kaldırılır ve yeni bir karar verilir.', duration_tr='Çıkışa veya yeni bir karara kadar' where code='V162';
update public.security_codes set title_tr='Ayrıntılı İnceleme', description_tr='Girişte ayrıntılı incelemeye (risk analizi / Risk Analysis) ihtiyaç duyulan yabancılara sınır polisi tarafından konulur. İnceleme tamamlandıktan sonra kaldırılan veya uygun bir işlem yapılan geçici bir koddur.', how_to_remove_tr='Ayrıntılı inceleme için sınır polisi tarafından eklenir. İnceleme tamamlandıktan sonra: kaldırılır veya uygun bir işlem yapılır.', duration_tr='Geçici — inceleme yapılana kadar' where code='V163';
update public.security_codes set title_tr='Güvenlik Endişesi', description_tr='Sınır dışı etme kararı fiilen uygulanan (Sınır Dışı Edildi) yabancılara konulur. Kalıcı bir kayıt olarak kalır. Giriş yasağı süresi, bir yıl (basit ihlaller) ile 5-10 yıl (güvenlik tehdidi veya sahte belge) arasında değişir. İnternette en çok araştırılan kodlardan biridir.', how_to_remove_tr='Sınır dışı etme işleminin fiilen tamamlanmasının ardından, işlemi uygulayan yerel müdürlük tarafından kaldırılır.', duration_tr='Kalıcı — sınır dışı kaydı' where code='V164';
update public.security_codes set title_tr='Yanlış Beyan', description_tr='Yanlış beyanda bulunan veya sistemde birden fazla parmak izi kaydı olan geçici koruma kapsamındaki kişilere konulur. Geçici Koruma Yönetmeliği''nin 8. maddesine göre işlem görür. Ödemeyenlere kesilen idari para cezası N-169 olarak kaydedilir.', how_to_remove_tr='Geçici Koruma Yönetmeliği''nin 8. maddesine göre işlem görür. Ödemeyenlere kesilen idari para cezası N-169 olarak kaydedilir.', duration_tr='Belirsiz' where code='V165';
update public.security_codes set title_tr='Geçici Giriş', description_tr='Geçici izinle Türkiye''ye giriş yapan ve geçici koruma kapsamında olmayan yabancılara konulur. İzin süresinin bitiminden önce korumaya kayıt olunması veya ülkeden çıkılması gerekir. Uyulmaması halinde N-169 eklenir.', how_to_remove_tr='Geçici izin süresinin bitiminden önce geçici korumaya kayıt olmak veya ülkeden çıkmak. Ülkeden çıkılmaması veya kayıt olunmaması halinde: N-169 eklenir.', duration_tr='Geçici izin süresi' where code='V173';
update public.security_codes set title_tr='Tedavi Amaçlı Giriş', description_tr='Yalnızca tıbbi tedavi amacıyla Türkiye''ye giriş yapan Suriyelilere konulur. Tedavi bittikten sonra ülkeden çıkılması gerekir.', how_to_remove_tr='Tedavi bittikten sonra ülkeden çıkmak. Sınır dışı edilmesi halinde: yasal prosedürlere göre işlem görür.', duration_tr='Tedavi süresi' where code='V174';
update public.security_codes set title_tr='Çıkış ve Geri Dönüş', description_tr='Suriye''ye giriş-çıkış yapmak isteyen geçici koruma kapsamındaki kişilere uygulanır. Sınır polisi tarafından özel usullere göre yürütülür.', how_to_remove_tr='Suriye''ye giriş-çıkış yapmak isteyen geçici koruma kapsamındaki kişiler içindir. Sınır polisi tarafından yürütülür.', duration_tr='Süreklidir' where code='V175';
update public.security_codes set title_tr='Sığınma Engeli', description_tr='Beş yıllık engel.
Uluslararası koruma (sığınma) talebi, tüm itiraz yolları tükendikten sonra nihai olarak reddedilen yabancılara uygulanır. Yeni bir koruma başvurusunda bulunulmasını engeller. Göç İdaresi Genel Müdürlüğü tarafından incelenir.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğü''ne başvurulması.', duration_tr='Belirsiz' where code='V177';
update public.security_codes set title_tr='Gönüllü Geri Dönüş', description_tr='Türkiye''den gönüllü olarak ayrılan ve çıkışı resmi olarak kaydedilen, geçici koruma kapsamındaki Suriyelilere uygulanır. İl müdürlüğüne başvurulup onay alınmadıkça geri dönüşü engeller. V-145 koduyla ilişkilidir.', how_to_remove_tr='İl Göç İdaresi Müdürlüğü''ne başvurulması.', duration_tr='Belirsiz' where code='V181';
update public.security_codes set title_tr='Türkiye''yi terk etmesi için kendisine resmi davette (Terke Davet) bulunulan ve bu karara uyarak ülkeyi fiilen terk eden kişi', description_tr='V182 kodu, kişinin "Türkiye''yi terk etmesi için kendisine resmi davette (Terke Davet) bulunulan bir kişi" olduğunu belgelemek üzere yabancının kaydına işlenen bir koddur.', how_to_remove_tr=NULL, duration_tr=NULL where code='V182';
update public.security_codes set title_tr='Kod', description_tr='Uluslararası koruma talebi geri çekilmiş sayılan yabancılara uygulanır. Bunun nedeni; bildirime (periyodik parmak izine) uyulmaması, Göç İdaresi''nin izni olmaksızın ikamet yerinin değiştirilmesi veya belirlenen mülakata katılmama olabilir.', how_to_remove_tr='İl Göç İdaresi Müdürlüğü''ne başvurulması.', duration_tr='Belirsiz' where code='V198';
update public.security_codes set title_tr=NULL, description_tr='Suriye''ye çıkış yapan, yani kendi ülkesine geri dönen kişilere uygulanır.', how_to_remove_tr=NULL, duration_tr=NULL where code='V200';
update public.security_codes set title_tr='Engel Konulması Talebi', description_tr='Kişinin bulunduğu ilin talebiyle uygulanır; yani bu kişiye Göç İdaresi Genel Müdürlüğü tarafından engel kodlarının konulması gerektiği anlamına gelir.', how_to_remove_tr='Yalnızca Iraklılarla ilgilidir.', duration_tr=NULL where code='V205';
update public.security_codes set title_tr='Geçici Engel', description_tr='İkamet ihlali veya yasa dışı çıkış nedeniyle yabancılara geçici engel olarak uygulanır. Nispeten yeni bir koddur ve Göç İdaresi Genel Müdürlüğü tarafından incelenir.', how_to_remove_tr='Göç İdaresi Genel Müdürlüğü''ne başvurulması.', duration_tr='Geçici' where code='V210';
update public.security_codes set title_tr='İdari Karar', description_tr='Ankara''daki Göç İdaresi Genel Müdürlüğü tarafından haklarında idari karar (idari parmak izi) verilen yabancılara uygulanır. İl veya Genel Müdürlük tarafından incelenir.', how_to_remove_tr='İl veya Göç İdaresi Genel Müdürlüğü''ne başvurulması.', duration_tr='Belirsiz' where code='V215';
update public.security_codes set title_tr='Giriş ve Çıkış İzni', description_tr='Geçici giriş/çıkış izni verilip bilinmeyen bölgelere giden Suriyeliler.', how_to_remove_tr=NULL, duration_tr=NULL where code='V216';
update public.security_codes set title_tr='Kamu görevlisine mukavemet kodu', description_tr='Bu kod, bir yabancının resmi görevini ifa eden bir güvenlik görevlisine veya kamu görevlisine (polis, jandarma veya göç idaresi personeli gibi) karşı fiziksel ya da sözlü direnme veya mukavemet içeren bir olayın meydana gelmesi durumunda yabancının kaydına işlenir. Bu kod ancak, yasal bir işlemin (arama, gözaltı veya sınır dışı etme gibi) uygulanmasını engellemeye yönelik mukavemet halini belgeleyen resmi bir polis tutanağına ya da Cumhuriyet Savcılığı bildirimine dayanılarak işlenir.', how_to_remove_tr=NULL, duration_tr=NULL where code='v217';
update public.security_codes set title_tr='Üçüncü ülke', description_tr='Üçüncü bir ülkeye çıkış yapan kişiye konulur.', how_to_remove_tr='Çalışma Bakanlığına veya yerel il müdürlüğüne başvurulması.', duration_tr='Belirsiz' where code='V224';
update public.security_codes set title_tr='Koruma başvurusunun geri çekilmesi', description_tr='Uluslararası koruma başvurusunu, bunun yerine normal bir ikamet izni almak amacıyla kendi isteğiyle geri çeken yabancılara konulur. Kalıcı kayıt olarak tutulur. Genellikle geri alınamaz — iltica hakkından kesin bir feragat olarak kabul edilir.', how_to_remove_tr='Genellikle geri alınamaz. Koruma başvurusundan gönüllü feragat hali olarak kaydedilir.', duration_tr='Kalıcı — kayıt' where code='V228';
update public.security_codes set title_tr='Bakanlık onayı', description_tr='İkamet başvurusu için İçişleri Bakanlığından ön onay alınması gereken yabancılara konulur. Genellikle muvazaalı (danışıklı) evlilik şüphesi veya geçmiş bir güvenlik dosyasıyla ilişkilidir. Onay alınmadan hiçbir ikamet izni verilmez. Muvazaalı evlilik şüphesi sabit olursa V-68 kaldırılır ve V-70 eklenir.', how_to_remove_tr='Yerel il müdürlüğüne (İl Müdürlüğü) başvurulması. Arşiv dosyaları incelenir — muvazaalı evlilik dışında bir güvenlik sorunu bulunmazsa V-68 kaldırılır ve V-70 eklenir. İkamet başvurusu yapıldığında durum yeniden değerlendirilir.', duration_tr='Belirsiz — inceleme yapılana kadar' where code='V68';
update public.security_codes set title_tr='İkamet iptali', description_tr='İkamet izni (süresinin dolması, gerekçesinin ortadan kalkması veya idari bir karar nedeniyle) iptal edilen yabancılara konulur. Ülkeden çıkış yapılması ve ikamet belgesinin sınır polisine teslim edilmesi gerekir. Sürenin aşılması halinde, aşım süresine göre Ç kodu + N-120 idari para cezası hesaplanır.', how_to_remove_tr='Çıkışta: İkamet belgesi sınır polisine teslim edilir ve kod kaldırılır. Sürenin aşılması halinde: Aşım süresine göre Ç cezası + ödemeyenler için N-120 hesaplanır. Yeni ikamet başvurusunda: Yerel il müdürlüğü tarafından kaldırılır.', duration_tr='Çıkışa veya durumun düzeltilmesine kadar' where code='V69';
update public.security_codes set title_tr='Muvazaalı evlilik', description_tr='YUKK 54/1-ı maddesi uyarınca ikamet izni veya Türk vatandaşlığı elde etmek amacıyla muvazaalı evlilik yaptığından şüphelenilen yabancılara konulur. İkamet izni iptal edilir ve evliliğin gerçekliği soruşturulur. Soruşturma evliliğin gerçek olduğunu kanıtlarsa kod kaldırılır.', how_to_remove_tr='Soruşturma, evliliğin gerçek ve aile kurma amaçlı olduğunu kanıtlarsa kod kaldırılır. Çıkışta: Genel kurallara göre işlem yapılır.', duration_tr='Evliliğin gerçekliği kanıtlanana kadar' where code='V70';
update public.security_codes set title_tr='Bilinmeyen adres', description_tr='İkamet adresindeki değişikliği göç idaresine bildirmeyen veya yanlış adres beyanında bulunan yabancılara konulur. Kaldırılması için N-97 idari para cezasının ödenmesi şarttır. Ödeme yapıldığında V-71 ve N-97 birlikte kaldırılır ve ikamet başvurusu işleme alınır.', how_to_remove_tr='Adres değişikliğini bildirmeme cezasının (N-97) ödenmesi. Ödemeden sonra V-71 ve N-97 birlikte kaldırılır ve ikamet başvurusu işleme alınır.', duration_tr='Cezanın ödenmesine kadar' where code='V71';
update public.security_codes set title_tr='Çıkış bildirimi', description_tr='Türkiye''den çıkışları halinde ilgili Bakanlığa veya yetkili valiliğe bildirim yapılması gereken yabancılara konulur. Çıkış talebinin kaydedilmesinden sonra eklenir ve yerel il müdürlüğü ile yetkili makam arasındaki koordinasyonla yürütülür.', how_to_remove_tr='Çıkış talebinin kaydedilmesinden sonra eklenir. Yerel il müdürlüğü ve Bakanlık/Valilik tarafından yürütülür.', duration_tr='Belirsiz' where code='V74';
update public.security_codes set title_tr='Ahıska değil', description_tr='Ahıska Türkleri sıfatıyla ikamet başvurusunda bulunan ancak bu kategoriye ait olmadığı anlaşılan yabancılara konulur. Yerel göç idaresi müdürlüğü tarafından incelenir.', how_to_remove_tr='Yerel göç idaresi müdürlüğüne başvurulması.', duration_tr='Belirsiz' where code='V77';
update public.security_codes set title_tr='Şartlı giriş', description_tr='Türkiye''ye şartlı olarak, giriş tarihinden itibaren 10 gün içinde ikamet izni çıkarma taahhüdüyle giriş yapan yabancılara konulur. Bu süre içinde başvuru yapılmazsa: Kişiye çıkış yapması bildirilir ve kod V-157 ile değiştirilir.', how_to_remove_tr='Şartlı girişten itibaren 10 gün içinde ikamet başvurusunda bulunulması. İkamet izni alındığında kod kaldırılır. Başvuru yapılmazsa: Çıkış yapması bildirilir ve kod V-157 ile değiştirilir.', duration_tr='Girişten itibaren 10 gün' where code='V84';
update public.security_codes set title_tr='Gönüllü Geri Dönüş', description_tr='Türkiye''yi gönüllü olarak terk eden (kendi iradeleriyle Suriye''ye dönen) geçici koruma kapsamındaki Suriyelilere uygulanır. İl müdürlüğüne başvurulup müdürlüğün onayı alınmadıkça Türkiye''ye tekrar girişi engeller.', how_to_remove_tr='Türkiye''ye dönmek istenildiğinde: Kişinin bulunduğu yerdeki il müdürlüğüne başvuru yapılır ve durum değerlendirilir. Kod, il müdürlüğünün kararıyla kaldırılır.', duration_tr='Belirsiz' where code='V87';
update public.security_codes set title_tr='Çalışma İzni İptali', description_tr='Çalışma izni iptal edilen (işi bırakma, şirketin iflası veya idari bir karar nedeniyle) yabancılara uygulanır. V-69 koduna benzer, ancak çalışma iznine özgüdür. Ülkeden çıkış yapılması veya durumun düzeltilmesi gerekir.', how_to_remove_tr='Ülkeden çıkışta: Çalışma belgesi sınır polisine teslim edilir ve kod kaldırılır. Süre aşımı durumunda: Ç + N-120 cezası hesaplanır. Yeni ikamet/çalışma başvurusu yapıldığında: Müdürlük tarafından kaldırılır.', duration_tr='Ülkeden çıkışa veya durumun düzeltilmesine kadar' where code='V88';
update public.security_codes set title_tr='Geri Kabul', description_tr='Uluslararası geri kabul anlaşmaları (Geri Kabul Anlaşmaları) kapsamında Türkiye''ye geri kabulü gerçekleştirilen yabancılara uygulanır. Kişinin teslim alındığı ildeki il müdürlüğü tarafından yönetilir.', how_to_remove_tr='Kişinin teslim alındığı ildeki il müdürlüğü tarafından yürütülür.', duration_tr='Belirsiz' where code='V89';
update public.security_codes set title_tr='Geçici Koruma', description_tr='Geçici koruma kapsamındaki kişilere (genellikle Suriyeliler) durumlarını belgelemek amacıyla uygulanır. Kayıtlı olunan ilden ayrılmadan önce il müdürlüğünden özel bir seyahat izni alınmasını gerektirir.', how_to_remove_tr='Geçici koruma kapsamındaki kişiler için il müdürlüğünden çıkış izni alınması.', duration_tr='Sürekli — izin gerektirir' where code='V91';
update public.security_codes set title_tr='Çift Kayıt', description_tr='Göç idaresi sisteminde birden fazla kaydı bulunan (mükerrer parmak izi veya kimlik) yabancılara uygulanır. Mükerrer kaydın düzeltilmesi ve dosyaların il müdürlüğü tarafından birleştirilmesi gerekir.', how_to_remove_tr='Mükerrer kaydın il müdürlüğü tarafından düzeltilmesi.', duration_tr='Düzeltme yapılana kadar' where code='V92';
commit;
